def smartNumber(n):
    def is_prime(num):
        if num < 2:
            return False
        for i in range(2, int(num**0.5) + 1):
            if num % i == 0:
                return False
        return True
    primes = []
    num = 2
    while len(primes) < n + 2:
        if is_prime(num):
            primes.append(num)
        num += 1
    product = 1
    for i in range(len(primes)):
        product *= primes[i]
    return product

smartNumber(1) == 30
smartNumber(50) == 273
smartNumber(1000) == 2664

